/**
 * fetchModel - Lấy dữ liệu từ server
 * @param {string} url - Đường dẫn API (ví dụ: "/user/list")
 * @returns {Promise} - Trả về dữ liệu JSON dưới dạng { data: ... }
 */
function fetchModel(url) {
  return new Promise((resolve, reject) => {
    // Gọi API tới server (mặc định là localhost:3000 nếu không ghi host)
    fetch(url)
      .then((response) => {
        if (!response.ok) {
          // Nếu lỗi (404, 500...), bắn lỗi về phía catch
          reject(new Error(`HTTP error! Status: ${response.status}`));
        } else {
          return response.json(); // Chuyển đổi phản hồi sang JSON
        }
      })
      .then((data) => {
        // Trả về object có thuộc tính data như đề bài yêu cầu
        resolve({ data: data });
      })
      .catch((error) => {
        console.error("Fetch error:", error);
        reject(error);
      });
  });
}

export default fetchModel;
